var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"으랏차! 다 덤벼! 오랜만의 활약이라고!","JPN":"おりゃああ！　みんなかかってこい！　久しぶりの活躍だあ！","ENG":"Hiyaahh! Who’s next?! It’s been a long time in battle!","TWN":"嘿咻！來吧！好久沒有大展身手了！"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"생각 없이 뛰쳐나가는 버릇은 여전하네, 고개 안 숙여?","JPN":"考えもなく飛び出す癖は相変わらずね。頭下げないの？","ENG":"You still haven’t fixed your habit of charging recklessly. Keep your head down!","TWN":"你衝動的老毛病都沒變呢，還不把頭低下？"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"왜? 아주 기어다니라고 하지?","JPN":"なに？　いっそ這って行けって言えば？","ENG":"Why don’t you just tell me to crawl all the way then?","TWN":"為什麼？這樣太慢啦！"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"알아서 피해서 쏴! 난 앞으로 간다!","JPN":"適当に避けて撃てよ！　俺は前に行く！","ENG":"I’m going in! Try not to shoot me, okay?","TWN":"我自己會避開子彈再開槍的！先衝囉！"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저 멍청이가 진짜……","JPN":"あのバカが……","ENG":"Ugh, that idiot!","TWN":"那個傻妞真的是……"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"리, 린이 많이 고생하네……","JPN":"り、リンも苦労するね……","ENG":"D-don’t stress out too much, Lin...","TWN":"曉…曉琳你就辛苦一點吧……"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그래도 이번 작전까지만 힘내자. 우리도 더 강해질 방법을 찾았다고 했잖아.","JPN":"今回の作戦までは頑張ろう。私たちがもっと強くなれる方法も見つけたって言ってたじゃない。","ENG":"Still, let’s pull through this mission. I heard we would find a way to make us stronger.","TWN":"就努力撐過這次作戰吧，不是說有找到可以讓我們變得更強的方法嗎？"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장이 한 말 말이야?","JPN":"隊長が言ってたこと？","ENG":"Is that what Cap said?","TWN":"是隊長說的嗎？"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"확실히 우린 정식 라이선스도 받았고 리플레이서로부터 자유도 되찾았어.","JPN":"確かに私たちは正式ライセンスももらったし、リプレイサーから自由も取り戻したよ。","ENG":"To be fair, we received our official licenses and gained independence from the Replacers.","TWN":"我們確實已經取得特遣勢力證書，也從克隆集團手中奪回自由。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장은 항상 자기가 한 말을 지켰지만…… 최근에 우리가 만난 적들은 상식을 벗어나 있잖아.","JPN":"隊長はいつも自分が言ったことは守ってくれたけど……最近私たちが遭遇した敵は常識の範囲を超えてるじゃない。","ENG":"She’s always kept her promises... But the enemies we’ve been facing lately have been defying all logic.","TWN":"隊長是一個說到做到的人……但我們最近遇到的敵人根本都超出想像。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그런 적들과 싸울 만큼 강해진다는 게 가능할까?","JPN":"そんな敵と戦えるほど強くなるなんてあり得る？","ENG":"Is it even possible to become strong enough to fight such enemies?","TWN":"有可能強到足以和那樣的敵人交手嗎？"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"쉬, 쉽진 않겠지만…… 네 말대로 대장은 자기가 한 말을 지켰잖아.","JPN":"か、簡単じゃないとは思うけど……リンが言ったように隊長は自分言ったことを守ってきたじゃない。","ENG":"I-it won’t be easy... But as you just said, Cap has always kept her promises.","TWN":"是…是不容易……但就像你說的，隊長是說到做到的人。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그리고 이번에 약속을 한 건 대장이 아니라 사장님이래.","JPN":"それに、今回約束をしたのは隊長じゃなくて、社長なんだって。","ENG":"Also, I heard that it was the Boss who made the promise this time, not Cap.","TWN":"而且這次不是隊長說的，是老闆說的。"},"stage":{"bg":"ROOFTOP","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"……사장님이?","JPN":"……社長が？","ENG":"…Boss?","TWN":"……老闆？"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그럼 뭐……. 속는 셈 치고 믿어 봐도 될 것 같네.","JPN":"へえ、それじゃあ……騙されたと思って信じてみてもいいかもね。","ENG":"If that’s the case... I’m willing to take a chance and see where things go.","TWN":"好吧……頂多當作被騙一次，就姑且相信吧。"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 왜 그런 눈으로 쳐다 봐?","JPN":"な、何よ？　なんでそんな目で見るの？","ENG":"W-what? Why are you looking at me like that?","TWN":"你…你幹嘛，幹嘛那樣看我？"},"stage":{"bg":"ROOFTOP","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};